module binary_down_counter(
    input wire clk,
    input wire rst_n,
    input wire en,
    output reg [3:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        count <= 4'd15;
    else if (en)
        count <= count - 4'd1;
end

endmodule
